use std::cmp::Ordering;

#[derive(Eq, PartialEq, Clone, Debug)]
struct Node {
    position: (usize, usize),
    g: usize,
    h: usize,
    parent: Option<(usize, usize)>,
}

impl Ord for Node {
    fn cmp(&self, other: &Self) -> Ordering {
        (other.g + other.h).cmp(&(self.g + self.h))
    }
}

impl PartialOrd for Node {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

fn manhattan_distance(a: (usize, usize), b: (usize, usize)) -> usize {
    ((a.0 as isize - b.0 as isize).abs() + (a.1 as isize - b.1 as isize).abs()) as usize
}

fn find_path_in_maze(maze: Vec<Vec<i32>>, start: (usize, usize), end: (usize, usize)) -> Option<Vec<(usize, usize)>> {
    let rows = maze.len();
    if rows == 0 {
        return None;
    }
    let cols = maze[0].len();
    if cols == 0 {
        return None;
    }

    let mut open_set = BinaryHeap::new();
    let mut closed_set = HashSet::new();
    let mut path = Vec::new();

    open_set.push(Node {
        position: start,
        g: 0,
        h: manhattan_distance(start, end),
        parent: None,
    });

    while let Some(current_node) = open_set.pop() {
        if current_node.position == end {
            let mut current = current_node.position;
            path.push(current);
            while let Some(parent) = current_node.parent {
                path.push(parent);
                current = parent;
            }
            path.reverse();
            return Some(path);
        }

        closed_set.insert(current_node.position);

        for (dx, dy) in &[(0, 1), (1, 0), (0, -1), (-1, 0)] {
            let x = current_node.position.0 as isize + dx;
            let y = current_node.position.1 as isize + dy;

            if x >= 0 && x < rows as isize && y >= 0 && y < cols as isize {
                let new_pos = (x as usize, y as usize);
                if maze[new_pos.0][new_pos.1] == 1 || closed_set.contains(&new_pos) {
                    continue;
                }

                let g = current_node.g + 1;
                let h = manhattan_distance(new_pos, end);
                let mut found_in_open = false;

                for node in open_set.iter() {
                    if node.position == new_pos && node.g <= g {
                        found_in_open = true;
                        break;
                    }
                }

                if !found_in_open {
                    open_set.push(Node {
                        position: new_pos,
                        g,
                        h,
                        parent: Some(current_node.position),
                    });
                }
            }
        }
    }

    None
}
