public class BloomFilter {
    private final BitSet bitSet;
    private final int size;
    private final MessageDigest[] hashFunctions;

    public BloomFilter(int size, int numHashFunctions) throws NoSuchAlgorithmException {
        this.bitSet = new BitSet(size);
        this.size = size;
        this.hashFunctions = new MessageDigest[numHashFunctions];
        for (int i = 0; i < numHashFunctions; i++) {
            hashFunctions[i] = MessageDigest.getInstance("SHA-256");
        }
    }

    public void add(String email) {
        for (int i = 0; i < hashFunctions.length; i++) {
            byte[] hash = hashFunctions[i].digest(email.getBytes());
            int index = Math.abs(new String(hash).hashCode()) % size;
            bitSet.set(index, true);
        }
    }

    public boolean checkEmailMembership(String email) {
        for (int i = 0; i < hashFunctions.length; i++) {
            byte[] hash = hashFunctions[i].digest(email.getBytes());
            int index = Math.abs(new String(hash).hashCode()) % size;
            if (!bitSet.get(index)) {
                return false;
            }
        }
        return true;
    }
