function findCentroids(dataPoints, k) {
    if (dataPoints.length === 0 || k <= 0) return [];

    // Initialize centroids randomly
    let centroids = [];
    for (let i = 0; i < k; i++) {
        const randomIndex = Math.floor(Math.random() * dataPoints.length);
        centroids.push({ ...dataPoints[randomIndex] });
    }

    let clusters = new Array(k).fill().map(() => []);
    let changed;

    do {
        changed = false;

        // Clear clusters
        clusters = new Array(k).fill().map(() => []);

        // Assign each point to the nearest centroid
        for (const point of dataPoints) {
            let minDist = Infinity;
            let clusterIndex = 0;

            for (let i = 0; i < k; i++) {
                const dist = Math.sqrt(
                    Math.pow(point.x - centroids[i].x, 2) + 
                    Math.pow(point.y - centroids[i].y, 2)
                );

                if (dist < minDist) {
                    minDist = dist;
                    clusterIndex = i;
                }
            }

            clusters[clusterIndex].push(point);
        }

        // Update centroids
        for (let i = 0; i < k; i++) {
            if (clusters[i].length === 0) continue;

            const sum = clusters[i].reduce((acc, point) => {
                acc.x += point.x;
                acc.y += point.y;
                return acc;
            }, { x: 0, y: 0 });

            const newX = sum.x / clusters[i].length;
            const newY = sum.y / clusters[i].length;

            if (centroids[i].x !== newX || centroids[i].y !== newY) {
                centroids[i] = { x: newX, y: newY };
                changed = true;
            }
        }
    } while (changed);

    return centroids;
}
