fn find_all_scc(graph: &Vec<Vec<usize>>) -> Vec<Vec<usize>> {
    let n = graph.len();
    let mut visited = vec![false; n];
    let mut order = Vec::new();

    // First pass to record the finishing order
    for i in 0..n {
        if !visited[i] {
            dfs(i, graph, &mut visited, &mut order);
        }
    }

    // Reverse the graph
    let mut reversed_graph = vec![Vec::new(); n];
    for (u, neighbors) in graph.iter().enumerate() {
        for &v in neighbors {
            reversed_graph[v].push(u);
        }
    }

    // Second pass on reversed graph in reverse order
    let mut visited = vec![false; n];
    let mut components = Vec::new();

    for &u in order.iter().rev() {
        if !visited[u] {
            let mut component = Vec::new();
            dfs(u, &reversed_graph, &mut visited, &mut component);
            components.push(component);
        }
    }

    components
}

