#include <stdlib.h>

typedef struct Interval {
    int low;
    int high;
} Interval;

typedef struct ITNode {
    Interval *interval;
    int max;
    struct ITNode *left, *right;
} ITNode;

ITNode* newNode(Interval interval) {
    ITNode* temp = (ITNode*)malloc(sizeof(ITNode));
    temp->interval = (Interval*)malloc(sizeof(Interval));
    temp->interval->low = interval.low;
    temp->interval->high = interval.high;
    temp->max = interval.high;
    temp->left = temp->right = NULL;
    return temp;
}

ITNode* insert(ITNode* root, Interval interval) {
    if (root == NULL)
        return newNode(interval);

    int l = root->interval->low;

    if (interval.low < l)
        root->left = insert(root->left, interval);
    else
        root->right = insert(root->right, interval);

    if (root->max < interval.high)
        root->max = interval.high;

    return root;
}

void mergeIntervals(Interval *a, Interval b) {
    if (b.low < a->low) a->low = b.low;
    if (b.high > a->high) a->high = b.high;
}

ITNode* overlapSearch(ITNode* root, Interval interval) {
    if (root == NULL) return NULL;

    if (root->interval->low <= interval.high && interval.low <= root->interval->high)
        return root;

    if (root->left != NULL && root->left->max >= interval.low)
        return overlapSearch(root->left, interval);

    return overlapSearch(root->right, interval);
}

ITNode* deleteNode(ITNode* root, Interval interval) {
    if (root == NULL) return NULL;

    if (interval.low < root->interval->low)
        root->left = deleteNode(root->left, interval);
    else if (interval.low > root->interval->low)
        root->right = deleteNode(root->right, interval);
    else {
        if (root->left == NULL) {
            ITNode* temp = root->right;
            free(root->interval);
            free(root);
            return temp;
        } else if (root->right == NULL) {
            ITNode* temp = root->left;
            free(root->interval);
            free(root);
            return temp;
        }

        ITNode* temp = root->right;
        while (temp->left != NULL)
            temp = temp->left;

        root->interval->low = temp->interval->low;
        root->interval->high = temp->interval->high;
        root->right = deleteNode(root->right, *temp->interval);
    }
    return root;
}

void updateMax(ITNode* root) {
    if (root == NULL) return;

    updateMax(root->left);
    updateMax(root->right);

    root->max = root->interval->high;
    if (root->left != NULL && root->left->max > root->max)
        root->max = root->left->max;
    if (root->right != NULL && root->right->max > root->max)
        root->max = root->right->max;
}

ITNode* interval_insert(ITNode* root, Interval interval) {
    ITNode* overlap = overlapSearch(root, interval);
    while (overlap != NULL) {
        mergeIntervals(overlap->interval, interval);
        interval = *(overlap->interval);
        root = deleteNode(root, interval);
        overlap = overlapSearch(root, interval);
    }
    root = insert(root, interval);
    updateMax(root);
    return root;
}
