import java.util.Arrays;

public class LongestRepeatedSubstring {
    public static String findLongestRepeatedSubstring(String text) {
        if (text == null || text.length() == 0) {
            return "";
        }

        int n = text.length();
        int[] suffixArray = buildSuffixArray(text);
        int[] lcp = buildLCPArray(text, suffixArray);

        int maxLength = 0;
        int startIndex = -1;

        for (int i = 0; i < n - 1; i++) {
            if (lcp[i] > maxLength) {
                maxLength = lcp[i];
                startIndex = suffixArray[i];
            }
        }

        return maxLength > 0 ? text.substring(startIndex, startIndex + maxLength) : "";
    }

    private static int[] buildSuffixArray(String text) {
        int n = text.length();
        Suffix[] suffixes = new Suffix[n];

        for (int i = 0; i < n; i++) {
            suffixes[i] = new Suffix(i, text.charAt(i) - 'a', (i + 1 < n) ? text.charAt(i + 1) - 'a' : -1);
        }

        Arrays.sort(suffixes);

        int[] ind = new int[n];
        for (int k = 4; k < 2 * n; k *= 2) {
            int rank = 0;
            int prevRank = suffixes[0].rank[0];
            suffixes[0].rank[0] = rank;
            ind[suffixes[0].index] = 0;

            for (int i = 1; i < n; i++) {
                if (suffixes[i].rank[0] == prevRank && suffixes[i].rank[1] == suffixes[i - 1].rank[1]) {
                    prevRank = suffixes[i].rank[0];
                    suffixes[i].rank[0] = rank;
                } else {
                    prevRank = suffixes[i].rank[0];
                    suffixes[i].rank[0] = ++rank;
                }
                ind[suffixes[i].index] = i;
            }

            for (int i = 0; i < n; i++) {
                int nextIndex = suffixes[i].index + k / 2;
                suffixes[i].rank[1] = (nextIndex < n) ? suffixes[ind[nextIndex]].rank[0] : -1;
            }

            Arrays.sort(suffixes);
        }

        int[] suffixArray = new int[n];
        for (int i = 0; i < n; i++) {
            suffixArray[i] = suffixes[i].index;
        }

        return suffixArray;
    }

    private static int[] buildLCPArray(String text, int[] suffixArray) {
        int n = suffixArray.length;
        int[] lcp = new int[n];
        int[] invSuffix = new int[n];

        for (int i = 0; i < n; i++) {
            invSuffix[suffixArray[i]] = i;
        }

        int k = 0;
        for (int i = 0; i < n; i++) {
            if (invSuffix[i] == n - 1) {
                k = 0;
                continue;
            }

            int j = suffixArray[invSuffix[i] + 1];
            while (i + k < n && j + k < n && text.charAt(i + k) == text.charAt(j + k)) {
                k++;
            }

            lcp[invSuffix[i]] = k;
            if (k > 0) {
                k--;
            }
        }

        return lcp;
    }

    static class Suffix implements Comparable<Suffix> {
        int index;
        int[] rank = new int[2];

        public Suffix(int index, int rank0, int rank1) {
            this.index = index;
            this.rank[0] = rank0;
            this.rank[1] = rank1;
        }

        @Override
        public int compareTo(Suffix other) {
            return (this.rank[0] == other.rank[0]) ? Integer.compare(this.rank[1], other.rank[1])
                    : Integer.compare(this.rank[0], other.rank[0]);
        }
    }
