using namespace std;

class SuffixTreeNode {
public:
    int start;
    int* end;
    SuffixTreeNode* children[256];
    SuffixTreeNode* suffixLink;
    int suffixIndex;

    SuffixTreeNode(int start, int* end, SuffixTreeNode* link) : start(start), end(end), suffixLink(link), suffixIndex(-1) {
        fill_n(children, 256, nullptr);
    }
};

class SuffixTree {
private:
    string input;
    SuffixTreeNode* root;
    SuffixTreeNode* lastNewNode;
    SuffixTreeNode* activeNode;
    int activeEdge;
    int activeLength;
    int remainingSuffixCount;
    int leafEnd;
    int* rootEnd;
    int* splitEnd;
    int size;

    SuffixTreeNode* newNode(int start, int* end) {
        SuffixTreeNode* node = new SuffixTreeNode(start, end, root);
        return node;
    }

    int edgeLength(SuffixTreeNode* node) {
        return *(node->end) - node->start + 1;
    }

    bool walkDown(SuffixTreeNode* node) {
        if (activeLength >= edgeLength(node)) {
            activeEdge += edgeLength(node);
            activeLength -= edgeLength(node);
            activeNode = node;
            return true;
        }
        return false;
    }

    void extendSuffixTree(int pos) {
        leafEnd = pos;
        remainingSuffixCount++;
        lastNewNode = nullptr;

        while (remainingSuffixCount > 0) {
            if (activeLength == 0) {
                activeEdge = pos;
            }

            if (activeNode->children[input[activeEdge]] == nullptr) {
                activeNode->children[input[activeEdge]] = newNode(pos, &leafEnd);

                if (lastNewNode != nullptr) {
                    lastNewNode->suffixLink = activeNode;
                    lastNewNode = nullptr;
                }
            } else {
                SuffixTreeNode* next = activeNode->children[input[activeEdge]];
                if (walkDown(next)) {
                    continue;
                }

                if (input[next->start + activeLength] == input[pos]) {
                    if (lastNewNode != nullptr && activeNode != root) {
                        lastNewNode->suffixLink = activeNode;
                        lastNewNode = nullptr;
                    }
                    activeLength++;
                    break;
                }

                splitEnd = new int;
                *splitEnd = next->start + activeLength - 1;

                SuffixTreeNode* split = newNode(next->start, splitEnd);
                activeNode->children[input[activeEdge]] = split;

                split->children[input[pos]] = newNode(pos, &leafEnd);
                next->start += activeLength;
                split->children[input[next->start]] = next;

                if (lastNewNode != nullptr) {
                    lastNewNode->suffixLink = split;
                }

                lastNewNode = split;
            }

            remainingSuffixCount--;

            if (activeNode == root && activeLength > 0) {
                activeLength--;
                activeEdge = pos - remainingSuffixCount + 1;
            } else if (activeNode != root) {
                activeNode = activeNode->suffixLink;
            }
        }
    }

    void setSuffixIndexByDFS(SuffixTreeNode* node, int labelHeight) {
        if (node == nullptr) return;

        bool isLeaf = true;
        for (int i = 0; i < 256; i++) {
            if (node->children[i] != nullptr) {
                isLeaf = false;
                setSuffixIndexByDFS(node->children[i], labelHeight + edgeLength(node->children[i]));
            }
        }

        if (isLeaf) {
            node->suffixIndex = size - labelHeight;
        }
    }

    void buildSuffixTree() {
        size = input.size();
        rootEnd = new int;
        *rootEnd = -1;

        root = newNode(-1, rootEnd);
        activeNode = root;
        activeEdge = -1;
        activeLength = 0;
        remainingSuffixCount = 0;
        leafEnd = -1;

        for (int i = 0; i < size; i++) {
            extendSuffixTree(i);
        }

        setSuffixIndexByDFS(root, 0);
    }

    void findLongestRepeatedSubstring(SuffixTreeNode* node, int labelHeight, int& maxHeight, int& substringStartIndex) {
        if (node == nullptr) return;

        if (node->suffixIndex == -1) {
            for (int i = 0; i < 256; i++) {
                if (node->children[i] != nullptr) {
                    findLongestRepeatedSubstring(node->children[i], labelHeight + edgeLength(node->children[i]), maxHeight, substringStartIndex);
                }
            }
        }

        if (node->suffixIndex == -1 && labelHeight > maxHeight) {
            maxHeight = labelHeight;
            substringStartIndex = *(node->end) - maxHeight + 1;
        }
    }

public:
    SuffixTree(string s) : input(s) {
        input += '$';
        buildSuffixTree();
    }

    string getLongestRepeatedSubstring() {
        int maxHeight = 0;
        int substringStartIndex = 0;
        findLongestRepeatedSubstring(root, 0, maxHeight, substringStartIndex);

        if (maxHeight == 0) {
            return "";
        } else {
            return input.substr(substringStartIndex, maxHeight);
        }
    }
};

string longest_repeated_substring(string s) {
    if (s.empty()) return "";
    SuffixTree st(s);
    return st.getLongestRepeatedSubstring();
}
