import java.util.*;
import java.util.Map.Entry;

public class HuffmanCompression {
    private static class HuffmanNode implements Comparable<HuffmanNode> {
        char character;
        int frequency;
        HuffmanNode left, right;

        HuffmanNode(char character, int frequency) {
            this.character = character;
            this.frequency = frequency;
        }

        HuffmanNode(char character, int frequency, HuffmanNode left, HuffmanNode right) {
            this.character = character;
            this.frequency = frequency;
            this.left = left;
            this.right = right;
        }

        boolean isLeaf() {
            return left == null && right == null;
        }

        @Override
        public int compareTo(HuffmanNode other) {
            return this.frequency - other.frequency;
        }
    }

    public static String compressData(String input) {
        if (input == null || input.isEmpty()) return "";

        // Calculate frequency of each character
        Map<Character, Integer> frequencyMap = new HashMap<>();
        for (char c : input.toCharArray()) {
            frequencyMap.put(c, frequencyMap.getOrDefault(c, 0) + 1);
        }

        // Build Huffman Tree
        HuffmanNode root = buildHuffmanTree(frequencyMap);

        // Generate Huffman Codes
        Map<Character, String> huffmanCodes = new HashMap<>();
        generateCodes(root, "", huffmanCodes);

        // Encode the input string
        StringBuilder compressed = new StringBuilder();
        for (char c : input.toCharArray()) {
            compressed.append(huffmanCodes.get(c));
        }

        // Serialize Huffman Tree and compressed data for reconstruction
        StringBuilder serializedTree = new StringBuilder();
        serializeTree(root, serializedTree);
        String treeString = serializedTree.toString();

        return treeString + "|" + compressed.toString();
    }

    private static HuffmanNode buildHuffmanTree(Map<Character, Integer> frequencyMap) {
        PriorityQueue<HuffmanNode> pq = new PriorityQueue<>();
        for (Entry<Character, Integer> entry : frequencyMap.entrySet()) {
            pq.add(new HuffmanNode(entry.getKey(), entry.getValue()));
        }

        while (pq.size() > 1) {
            HuffmanNode left = pq.poll();
            HuffmanNode right = pq.poll();
            HuffmanNode parent = new HuffmanNode('\0', left.frequency + right.frequency, left, right);
            pq.add(parent);
        }

        return pq.poll();
    }

    private static void generateCodes(HuffmanNode node, String code, Map<Character, String> huffmanCodes) {
        if (node == null) return;
        if (node.isLeaf()) {
            huffmanCodes.put(node.character, code.isEmpty() ? "0" : code);
            return;
        }
        generateCodes(node.left, code + "0", huffmanCodes);
        generateCodes(node.right, code + "1", huffmanCodes);
    }

    private static void serializeTree(HuffmanNode node, StringBuilder sb) {
        if (node == null) return;
        if (node.isLeaf()) {
            sb.append('1');
            sb.append(node.character);
            return;
        }
        sb.append('0');
        serializeTree(node.left, sb);
        serializeTree(node.right, sb);
    }
}
