fn merge_sort_list<T: PartialOrd + Clone>(head: Link<T>) -> Link<T> {
    if head.is_none() || head.as_ref().unwrap().next.is_none() {
        return head;
    }

    let (left, right) = split_list(head);
    let left_sorted = merge_sort_list(left);
    let right_sorted = merge_sort_list(right);
    merge(left_sorted, right_sorted)
}

fn split_list<T>(mut head: Link<T>) -> (Link<T>, Link<T>) {
    let mut fast = head.as_ref().map(|node| &node.next).unwrap_or(&None);
    let mut slow = &mut head;

    while fast.is_some() {
        fast = fast.as_ref().map(|node| &node.next).unwrap_or(&None);
        if fast.is_some() {
            fast = fast.as_ref().map(|node| &node.next).unwrap_or(&None);
            slow = &mut slow.as_mut().unwrap().next;
        }
    }

    let right = slow.as_mut().unwrap().next.take();
    (head, right)
}

fn merge<T: PartialOrd>(left: Link<T>, right: Link<T>) -> Link<T> {
    match (left, right) {
        (None, right) => right,
        (left, None) => left,
        (Some(mut left_node), Some(mut right_node)) => {
            if left_node.data <= right_node.data {
                left_node.next = merge(left_node.next.take(), Some(right_node));
                Some(left_node)
            } else {
                right_node.next = merge(Some(left_node), right_node.next.take());
                Some(right_node)
            }
        }
    }
}
