        if (parent[i] != i)
            parent[i] = find(parent[i]);
        return parent[i];
    }

    static void union(int x, int y) {
        int xRoot = find(x);
        int yRoot = find(y);

        if (rank[xRoot] < rank[yRoot])
            parent[xRoot] = yRoot;
        else if (rank[xRoot] > rank[yRoot])
            parent[yRoot] = xRoot;
        else {
            parent[yRoot] = xRoot;
            rank[xRoot]++;
        }
    }

    public static int findMinimumSpanningTree(int[][] graph) {
        int V = graph.length;
        Edge[] edges = new Edge[V * V];
        int edgeCount = 0;

        for (int i = 0; i < V; i++) {
            for (int j = i + 1; j < V; j++) {
                if (graph[i][j] != 0) {
                    Edge edge = new Edge();
                    edge.src = i;
                    edge.dest = j;
                    edge.weight = graph[i][j];
                    edges[edgeCount++] = edge;
                }
            }
        }

        edges = Arrays.copyOf(edges, edgeCount);
        Arrays.sort(edges);

        parent = new int[V];
        rank = new int[V];

        for (int i = 0; i < V; i++) {
            parent[i] = i;
            rank[i] = 0;
        }

        int mstWeight = 0;
        int e = 0;
        int i = 0;

        while (e < V - 1 && i < edgeCount) {
            Edge nextEdge = edges[i++];
            int x = find(nextEdge.src);
            int y = find(nextEdge.dest);

            if (x != y) {
                mstWeight += nextEdge.weight;
                union(x, y);
                e++;
            }
        }

        return mstWeight;
    }
