use rand::Rng;

fn is_prime_miller_rabin(num: u64) -> bool {
    if num <= 1 {
        return false;
    }
    if num <= 3 {
        return true;
    }
    if num % 2 == 0 {
        return false;
    }

    let mut d = num - 1;
    let mut s = 0;
    while d % 2 == 0 {
        d /= 2;
        s += 1;
    }

    let k = 5; // Number of iterations (higher = more accurate)
    let mut rng = rand::thread_rng();

    for _ in 0..k {
        let a = rng.gen_range(2..num - 1);
        let mut x = mod_exp(a, d, num);
        if x == 1 || x == num - 1 {
            continue;
        }

        let mut found = false;
        for __ in 0..s - 1 {
            x = mod_exp(x, 2, num);
            if x == num - 1 {
                found = true;
                break;
            }
        }
        if !found {
            return false;
        }
    }
    true
}

fn mod_exp(mut base: u64, mut exp: u64, modulus: u64) -> u64 {
    if modulus == 1 {
        return 0;
    }
    let mut result = 1;
    base %= modulus;
    while exp > 0 {
        if exp % 2 == 1 {
            result = (result * base) % modulus;
        }
        exp >>= 1;
        base = (base * base) % modulus;
    }
    result
}
